static Value *foldAddOneNotMaxAndCmp(ICmpInst *NotMaxCmp, ICmpInst *AddCmp,
                                     bool IsAnd,
                                     InstCombiner::BuilderTy &Builder) {
  // Pattern: (X != -1) && (X + 1 <= Y) --> X < Y
  //          (X == -1) || (X + 1 > Y) --> X >= Y
  ICmpInst::Predicate NotMaxPred = NotMaxCmp->getPredicate();
  Value *X, *Y;
  const APInt *C;
  // Match X != -1 or X == -1
  // Constant may be on either side because equality predicates are commutative.
  if (match(NotMaxCmp->getOperand(1), m_APInt(C))) {
    if (!C->isAllOnes())
      return nullptr;
    X = NotMaxCmp->getOperand(0);
  } else if (match(NotMaxCmp->getOperand(0), m_APInt(C))) {
    if (!C->isAllOnes())
      return nullptr;
    X = NotMaxCmp->getOperand(1);
  } else {
    return nullptr;
  }
  if (IsAnd) {
    if (NotMaxPred != ICmpInst::ICMP_NE)
      return nullptr;
  } else {
    if (NotMaxPred != ICmpInst::ICMP_EQ)
      return nullptr;
  }

  // Match add X, 1 and compare with Y
  ICmpInst::Predicate AddPred = AddCmp->getPredicate();
  Value *Add = nullptr;
  if (match(AddCmp->getOperand(0), m_Add(m_Specific(X), m_One())))
    Add = AddCmp->getOperand(0);
  else if (match(AddCmp->getOperand(1), m_Add(m_Specific(X), m_One()))) {
    Add = AddCmp->getOperand(1);
    // Swap predicate because the add is on RHS.
    AddPred = ICmpInst::getSwappedPredicate(AddPred);
  }
  if (!Add)
    return nullptr;

  // Determine Y: the other operand of the icmp (not the add)
  Y = (AddCmp->getOperand(0) == Add) ? AddCmp->getOperand(1) : AddCmp->getOperand(0);

  // Expected predicate for AND: ULE (since we want X+1 <= Y). For OR: UGT.
  if (IsAnd && AddPred != ICmpInst::ICMP_ULE)
    return nullptr;
  if (!IsAnd && AddPred != ICmpInst::ICMP_UGT)
    return nullptr;

  // Transform: X < Y for AND, X >= Y for OR.
  ICmpInst::Predicate NewPred = IsAnd ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
  return Builder.CreateICmp(NewPred, X, Y);
}
